window.gallery={init:function(){this.initPhotoSwipe()},initPhotoSwipe:function(){if(typeof PhotoSwipe=="undefined"){console.warn("PhotoSwipe 未載入");return}const e=document.querySelectorAll("a.gallery-link");if(!e.length)return;e.forEach((t,n)=>{t.addEventListener("click",t=>{t.preventDefault(),this.openGallery(e,n)})})},openGallery:function(e,t){const n=Array.from(e).map((e,t)=>{const n=e.querySelector("img");let s=e.dataset.pswpWidth?parseInt(e.dataset.pswpWidth):1200,o=e.dataset.pswpHeight?parseInt(e.dataset.pswpHeight):800;return n&&n.complete&&n.naturalWidth&&(s=n.naturalWidth,o=n.naturalHeight),{src:e.href,width:s,height:o,alt:n?.alt||`圖片 ${t+1}`,thumbSrc:n?.src||""}}),s=new PhotoSwipe({dataSource:n,index:t,bgOpacity:.9,closeOnVerticalDrag:!0,closeOnBackgroundClick:!0,arrowKeys:!0,wheelToZoom:!0,loop:!0,padding:{top:20,bottom:20,left:20,right:20}});s.init()}}